import React, { useCallback, useMemo, useState } from "react";
import { FiUsers, FiPlus, FiX } from "react-icons/fi";
import { useOutletContext } from "react-router-dom";
import DataTable from "../components/DataTable";
import UserForm from "../components/UserForm";
import { initialUsers } from "../utils/sampleData";

const Users = () => {
  const [data, setData] = useState(initialUsers);
  const [message, setMessage] = useState("");
  const [showForm, setShowForm] = useState(false);

  const { searchTerm } = useOutletContext();

  const deleteUser = useCallback((id) => {
    if (window.confirm("Delete this user?")) {
      setData((prev) => prev.filter((user) => user.id !== id));
      setMessage("User deleted successfully.");
    }
  }, []);

  const editUser = useCallback((user) => {
    setMessage(`Editing ${user.name}`);
  }, []);

  const activeCount = useMemo(
    () => data.filter((user) => user.status === "Active").length,
    [data]
  );

  const filteredUsers = useMemo(() => {
    const query = searchTerm.toLowerCase().trim();

    if (!query) return data;

    return data.filter(
      (user) =>
        user.name.toLowerCase().includes(query) ||
        user.email.toLowerCase().includes(query)
    );
  }, [data, searchTerm]);

  return (
    <div className="space-y-6">

      {/* Header */}
      <div className="rounded-2xl bg-white border border-slate-200 shadow-sm p-6 flex flex-wrap justify-between items-center">

        <div className="flex items-center gap-4">
          <div className="bg-blue-600 p-3 rounded-xl text-white">
            <FiUsers size={22} />
          </div>

          <div>
            <h2 className="text-xl font-bold text-slate-800">
              User Management
            </h2>

            <p className="text-sm text-slate-500">
              Manage all registered users
            </p>
          </div>
        </div>

        <div className="flex gap-3 items-center">

          <span className="bg-green-100 text-green-700 px-3 py-1 rounded-full text-sm font-semibold">
            {activeCount} Active
          </span>

          <button
            onClick={() => setShowForm(!showForm)}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2 rounded-lg transition"
          >
            {showForm ? <FiX /> : <FiPlus />}
            {showForm ? "Close" : "Create User"}
          </button>

        </div>
      </div>

      {/* Success Message */}

      {message && (
        <div className="bg-green-50 border border-green-200 text-green-700 rounded-lg px-4 py-3">
          {message}
        </div>
      )}

      {/* User Form */}

      {showForm && (
        <div className="rounded-2xl bg-white border border-slate-200 shadow-sm p-6">

          <h3 className="text-lg font-semibold mb-5">
            Create New User
          </h3>

          <UserForm
            onSubmitSuccess={() => {
              setMessage("User created successfully.");
              setShowForm(false);
            }}
          />

        </div>
      )}

      {/* User Table */}

      <div className="rounded-2xl bg-white border border-slate-200 shadow-sm p-6">

        {filteredUsers.length > 0 ? (
          <DataTable
            data={filteredUsers}
            onEdit={editUser}
            onDelete={deleteUser}
          />
        ) : (
          <div className="text-center py-10 text-slate-500">
            No users found.
          </div>
        )}

      </div>

    </div>
  );
};

export default Users;
